{"code":"import json, re
# load the clinical query result from the stored file
path = var_call_JqcfvD05Y4Be4hcdEU4loPEw
with open(path, 'r', encoding='utf-8') as f:
    data = json.load(f)

mapping = {}
barcodes = []
for rec in data:
    desc = rec.get('Patient_description') or ''
    hist = rec.get('histological_type') or None
    if not hist:
        continue
    hist_str = hist.strip()
    # skip histologies enclosed in square brackets
    if re.match(r'^\[.*\]$', hist_str):
        continue
    # extract TCGA barcode
    m = re.search(r'TCGA-[A-Z0-9]+-[A-Z0-9]+', desc)
    if not m:
        # try patient_id if looks like TCGA
        pid = rec.get('patient_id')
        if pid and isinstance(pid, str) and pid.startswith('TCGA'):
            barcode = pid
        else:
            continue
    else:
        barcode = m.group(0)
    # normalize barcode to uppercase
    barcode = barcode.upper()
    if barcode not in mapping:
        mapping[barcode] = hist_str
        barcodes.append(barcode)

out = {'barcodes': barcodes, 'mapping': mapping}
print('__RESULT__:')
print(json.dumps(out))"}
